using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private OrderService _sut = null!;

    [TestInitialize]
    public void Setup() => _sut = new OrderService();

    private static List<OrderItem> CreateItems(params (string Name, decimal Price, int Qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.Name, Price = i.Price, Quantity = i.Qty }).ToList();

    // ──── CreateOrder – happy paths ────

    [TestMethod]
    public void CreateOrder_WithSingleItem_ReturnsOrderWithCorrectTotal()
    {
        var items = CreateItems(("Widget", 9.99m, 3));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(29.97m, order.Total);
        Assert.AreEqual(1, order.Items.Count);
    }

    [TestMethod]
    public void CreateOrder_WithMultipleItems_SumsTotalCorrectly()
    {
        var items = CreateItems(("A", 10m, 2), ("B", 5m, 4));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreEqual(40m, order.Total); // (10*2) + (5*4)
    }

    [TestMethod]
    public void CreateOrder_AssignsUniqueId()
    {
        var items = CreateItems(("X", 1m, 1));

        var order1 = _sut.CreateOrder("c1", items);
        var order2 = _sut.CreateOrder("c2", items);

        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToRecentUtcTime()
    {
        var before = DateTime.UtcNow;
        var order = _sut.CreateOrder("c1", CreateItems(("X", 1m, 1)));
        var after = DateTime.UtcNow;

        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after);
    }

    // ──── CreateOrder – validation ────

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _sut.CreateOrder(null!, CreateItems(("X", 1m, 1))));
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _sut.CreateOrder("cust-1", null!));
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _sut.CreateOrder("cust-1", []));
    }

    // ──── GetOrder ────

    [TestMethod]
    public void GetOrder_ExistingId_ReturnsOrder()
    {
        var created = _sut.CreateOrder("c1", CreateItems(("X", 5m, 1)));

        var found = _sut.GetOrder(created.Id);

        Assert.IsNotNull(found);
        Assert.AreEqual(created.Id, found.Id);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        var result = _sut.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    // ──── GetOrdersByCustomer ────

    [TestMethod]
    public void GetOrdersByCustomer_ReturnsOnlyMatchingOrders()
    {
        _sut.CreateOrder("alice", CreateItems(("A", 1m, 1)));
        _sut.CreateOrder("bob",   CreateItems(("B", 2m, 1)));
        _sut.CreateOrder("alice", CreateItems(("C", 3m, 1)));

        var aliceOrders = _sut.GetOrdersByCustomer("alice");

        Assert.AreEqual(2, aliceOrders.Count);
        Assert.IsTrue(aliceOrders.All(o => o.CustomerId == "alice"));
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoMatches_ReturnsEmptyList()
    {
        _sut.CreateOrder("alice", CreateItems(("A", 1m, 1)));

        var result = _sut.GetOrdersByCustomer("unknown");

        Assert.AreEqual(0, result.Count);
    }
}

